// ===========================
// Configuration
// ===========================
// These values are loaded dynamically from firebase-config.json (generated by Terraform)
let API_URL = null;
let FIREBASE_CONFIG = null;

const POLL_INTERVAL_MS = 3000; // Poll every 3 seconds
const THROTTLE_MS = 30000; // 30 seconds between submissions
const MAX_POLL_ATTEMPTS = 150; // Stop polling after 7.5 minutes (to handle identity function retries)
const STATUS_UPDATE_INTERVAL_MS = 1000; // Update status message every second

// Load configuration from firebase-config.json (generated by Terraform)
async function loadConfig() {
  try {
    const response = await fetch("firebase-config.json");
    if (!response.ok) {
      throw new Error(`HTTP ${response.status}`);
    }
    const config = await response.json();

    // Set API URL from config
    API_URL = config.apiUrl;

    // Set Firebase config
    FIREBASE_CONFIG = {
      apiKey: config.apiKey,
      authDomain: config.authDomain,
      projectId: config.projectId,
      storageBucket: config.storageBucket,
      messagingSenderId: config.messagingSenderId,
      appId: config.appId,
    };

    console.log("Configuration loaded from firebase-config.json");
    console.log("API URL:", API_URL);
    return true;
  } catch (error) {
    console.error("Failed to load firebase-config.json:", error);
    console.error(
      "Please ensure terraform apply has been run to generate the configuration."
    );

    // Show user-friendly error
    const errorDiv = document.createElement("div");
    errorDiv.style.cssText =
      "position: fixed; top: 0; left: 0; right: 0; background: #dc3545; color: white; padding: 1rem; text-align: center; z-index: 9999;";
    errorDiv.innerHTML =
      "<strong>Configuration Error:</strong> firebase-config.json not found. Please ensure the deployment is complete.";
    document.body.prepend(errorDiv);

    return false;
  }
}

