// Address Verification Functions
// ===========================
function showAddressVerificationLoading() {
  elements.addressVerificationForm.style.display = "none";
  elements.addressVerificationResults.style.display = "none";
  elements.addressVerificationError.style.display = "none";
  elements.addressVerificationLoading.style.display = "block";
}

function showAddressVerificationResults(data) {
  elements.addressVerificationForm.style.display = "none";
  elements.addressVerificationLoading.style.display = "none";
  elements.addressVerificationError.style.display = "none";
  elements.addressVerificationResults.style.display = "block";

  const analysis = data.analysis || {};
  let html = "";

  // Business verification status (PRIMARY RESULT)
  const businessAtAddress = analysis.business_at_address;
  const businessStatus = businessAtAddress ? "✓ Verified" : "✗ Not Found";
  const businessStatusClass = businessAtAddress ? "success" : "error";
  html += `<div class="verification-status ${businessStatusClass}" style="padding: var(--space-md); border-radius: 8px; margin-bottom: var(--space-lg); background: ${
    businessAtAddress
      ? "var(--success-bg, #d4edda)"
      : "var(--error-bg, #f8d7da)"
  }; border: 1px solid ${
    businessAtAddress
      ? "var(--success-border, #c3e6cb)"
      : "var(--error-border, #f5c6cb)"
  };">`;
  html += `<h3 style="margin: 0 0 var(--space-sm) 0;">Business Verification: <strong>${escapeHtml(
    businessStatus
  )}</strong></h3>`;
  html += `<p style="margin: 0;">${escapeHtml(
    analysis.reasoning || "No reasoning provided"
  )}</p>`;
  html += `</div>`;

  // Street View link
  const geocoding = data.geocoding || {};
  const streetViewUrl = geocoding.street_view_url;
  if (streetViewUrl) {
    html += `<div style="margin-bottom: var(--space-lg);">`;
    html += `<a href="${escapeHtml(
      streetViewUrl
    )}" target="_blank" class="submit-button" style="display: inline-block; text-decoration: none; text-align: center;">`;
    html += `📍 View Address on Google Street View`;
    html += `</a>`;
    html += `</div>`;
  }

  // Fraud risk level
  const riskLevel = analysis.fraud_risk_level || "unknown";
  const riskColors = {
    low: "#28a745",
    medium: "#ffc107",
    high: "#dc3545",
  };
  const riskColor = riskColors[riskLevel] || "#6c757d";
  html += `<div style="padding: var(--space-md); border-radius: 8px; margin-bottom: var(--space-lg); border-left: 4px solid ${riskColor};">`;
  html += `<h4 style="margin: 0 0 var(--space-sm) 0;">Verification Risk Level: <span style="color: ${riskColor}; font-weight: bold; text-transform: uppercase;">${escapeHtml(
    riskLevel
  )}</span></h4>`;
  html += `<p style="margin: 0; color: var(--text-secondary);">${escapeHtml(
    analysis.reasoning || ""
  )}</p>`;
  html += `</div>`;

  // Fraud indicators
  const fraudIndicators = analysis.fraud_indicators || [];
  if (fraudIndicators.length > 0) {
    html += `<div style="margin-bottom: var(--space-lg);">`;
    html += `<h4>⚠️ Verification Concerns:</h4>`;
    html += `<ul style="margin: var(--space-sm) 0; padding-left: var(--space-lg);">`;
    fraudIndicators.forEach((indicator) => {
      html += `<li>${escapeHtml(indicator)}</li>`;
    });
    html += `</ul>`;
    html += `</div>`;
  }

  // Address type classifications
  html += `<div style="margin-bottom: var(--space-lg);">`;
  html += `<h4>Address Classification:</h4>`;
  html += `<ul style="margin: var(--space-sm) 0; padding-left: var(--space-lg);">`;
  if (analysis.is_virtual_workspace) {
    html += `<li style="color: var(--error-color, #dc3545);">⚠️ Virtual workspace/co-working space</li>`;
  }
  if (analysis.is_shipping_location) {
    html += `<li style="color: var(--error-color, #dc3545);">⚠️ Shipping/mailbox location (UPS/FedEx/PO Box)</li>`;
  }
  if (analysis.is_residential) {
    html += `<li style="color: var(--error-color, #dc3545);">⚠️ Residential address (red flag for business)</li>`;
  }
  if (
    !analysis.is_virtual_workspace &&
    !analysis.is_shipping_location &&
    !analysis.is_residential
  ) {
    html += `<li>✓ Appears to be a legitimate business address</li>`;
  }
  html += `</ul>`;
  html += `</div>`;

  // Key findings
  const keyFindings = analysis.key_findings || [];
  if (keyFindings.length > 0) {
    html += `<div style="margin-bottom: var(--space-lg);">`;
    html += `<h4>Key Findings:</h4>`;
    html += `<ul style="margin: var(--space-sm) 0; padding-left: var(--space-lg);">`;
    keyFindings.forEach((finding) => {
      html += `<li>${escapeHtml(finding)}</li>`;
    });
    html += `</ul>`;
    html += `</div>`;
  }

  // Confidence level
  html += `<div style="padding: var(--space-sm); background: var(--bg-secondary, #f8f9fa); border-radius: 4px; margin-top: var(--space-lg);">`;
  html += `<small style="color: var(--text-secondary);">Confidence: <strong>${escapeHtml(
    analysis.confidence || "unknown"
  )}</strong></small>`;
  html += `</div>`;

  // Search Results Section
  const searchResults = data.search_results?.queries || [];
  if (searchResults.length > 0) {
    // Query ID to human-readable labels
    const queryLabels = {
      business_name_and_address: "Business Name + Address (Exact Match)",
      business_name_and_address_flexible: "Business Name + Address (Flexible)",
      address_only: "Address Only",
      business_name_and_location: "Business Name + Location",
      business_reviews_ratings: "Reviews & Ratings",
      business_complaints_fraud: "Complaints & Fraud Reports",
    };

    // Query type to badge styling
    const typeStyles = {
      high_precision: {
        bg: "#e7f3ff",
        border: "#b3d9ff",
        label: "High Precision",
      },
      context: {
        bg: "#fff4e6",
        border: "#ffd699",
        label: "Context",
      },
      high_recall: {
        bg: "#e6f7e6",
        border: "#b3e6b3",
        label: "High Recall",
      },
    };

    // Calculate summary statistics
    const totalResults = searchResults.reduce(
      (sum, query) => sum + (query.hits?.length || 0),
      0
    );

    html += `<div style="margin-top: var(--space-xl); border-top: 2px solid var(--border-color, #dee2e6); padding-top: var(--space-lg);">`;
    html += `<h4 style="margin: 0 0 var(--space-sm) 0;">🔍 Search Results</h4>`;
    html += `<p style="color: var(--text-secondary); font-size: 0.9em; margin: 0 0 var(--space-md) 0;">`;
    html += `Found ${totalResults} total results across ${
      searchResults.length
    } search ${searchResults.length === 1 ? "query" : "queries"}.`;
    html += `</p>`;

    // Display each query
    searchResults.forEach((query, queryIndex) => {
      const queryId = query.id || `query_${queryIndex}`;
      const queryLabel =
        queryLabels[queryId] ||
        queryId.replace(/_/g, " ").replace(/\b\w/g, (l) => l.toUpperCase());
      const queryType = query.type || "unknown";
      const typeStyle = typeStyles[queryType] || {
        bg: "#f0f0f0",
        border: "#d0d0d0",
        label: queryType,
      };
      const hits = query.hits || [];
      const queryString = query.query || "";

      html += `<div style="margin-bottom: var(--space-lg); border: 1px solid ${typeStyle.border}; border-radius: 8px; background: ${typeStyle.bg}; overflow: hidden;">`;

      // Query header
      html += `<div style="padding: var(--space-md); border-bottom: 1px solid ${typeStyle.border};">`;
      html += `<div style="display: flex; justify-content: space-between; align-items: flex-start; flex-wrap: wrap; gap: var(--space-sm);">`;
      html += `<div style="flex: 1; min-width: 200px;">`;
      html += `<h5 style="margin: 0 0 var(--space-xs) 0; font-size: 1em;">${escapeHtml(
        queryLabel
      )}</h5>`;
      html += `<span style="display: inline-block; padding: 2px 8px; background: ${
        typeStyle.border
      }; border-radius: 4px; font-size: 0.75em; font-weight: 500; color: #333;">${escapeHtml(
        typeStyle.label
      )}</span>`;
      html += `</div>`;
      html += `<div style="text-align: right; flex-shrink: 0;">`;
      html += `<div style="font-size: 0.85em; color: var(--text-secondary);">${
        hits.length
      } result${hits.length === 1 ? "" : "s"}</div>`;
      html += `</div>`;
      html += `</div>`;
      html += `<div style="margin-top: var(--space-sm); font-size: 0.85em; color: var(--text-secondary); font-family: monospace; word-break: break-all;">`;
      html += `<strong>Query:</strong> ${escapeHtml(queryString)}`;
      html += `</div>`;
      html += `</div>`;

      // Query results
      if (hits.length > 0) {
        html += `<div style="padding: var(--space-md);">`;
        hits.forEach((hit, hitIndex) => {
          const title = hit.title || "Untitled";
          const url = hit.url || "#";
          const snippet = hit.snippet || "";

          html += `<div style="margin-bottom: var(--space-md); padding-bottom: var(--space-md); border-bottom: ${
            hitIndex < hits.length - 1
              ? "1px solid var(--border-color, #e0e0e0)"
              : "none"
          };">`;
          html += `<div style="margin-bottom: var(--space-xs);">`;
          html += `<a href="${escapeHtml(
            url
          )}" target="_blank" rel="noopener noreferrer" style="color: #0066cc; text-decoration: none; font-weight: 500; font-size: 0.95em;">`;
          html += `${hitIndex + 1}. ${escapeHtml(title)}`;
          html += `</a>`;
          html += `</div>`;
          html += `<div style="font-size: 0.8em; color: #006621; margin-bottom: var(--space-xs); word-break: break-all;">`;
          html += `${escapeHtml(url)}`;
          html += `</div>`;
          if (snippet) {
            html += `<div style="font-size: 0.85em; color: var(--text-secondary); line-height: 1.4;">`;
            html += `${escapeHtml(snippet)}`;
            html += `</div>`;
          }
          html += `</div>`;
        });
        html += `</div>`;
      } else {
        html += `<div style="padding: var(--space-md); color: var(--text-secondary); font-style: italic;">`;
        html += `No results found for this query.`;
        html += `</div>`;
      }

      html += `</div>`;
    });

    html += `</div>`;
  }

  elements.addressVerificationResultsContent.innerHTML = html;
}

function showAddressVerificationError(message) {
  elements.addressVerificationForm.style.display = "none";
  elements.addressVerificationLoading.style.display = "none";
  elements.addressVerificationResults.style.display = "none";
  elements.addressVerificationError.style.display = "block";

  elements.addressVerificationErrorMessage.textContent =
    formatUserFriendlyError(message);
}

function showAddressVerificationFieldError(fieldError, message) {
  if (!fieldError) return;

  if (message) {
    fieldError.textContent = message;
    if (fieldError.previousElementSibling) {
      fieldError.previousElementSibling.classList.add("error");
    }
  } else {
    fieldError.textContent = "";
    if (fieldError.previousElementSibling) {
      fieldError.previousElementSibling.classList.remove("error");
    }
  }
}

function resetAddressVerificationForm() {
  if (!elements.addressVerificationForm) return;

  elements.addressVerificationForm.style.display = "block";
  if (elements.addressVerificationLoading)
    elements.addressVerificationLoading.style.display = "none";
  if (elements.addressVerificationResults)
    elements.addressVerificationResults.style.display = "none";
  if (elements.addressVerificationError)
    elements.addressVerificationError.style.display = "none";

  elements.addressVerificationForm.reset();
  if (elements.businessNameError)
    showAddressVerificationFieldError(elements.businessNameError, null);
  if (elements.streetAddressError)
    showAddressVerificationFieldError(elements.streetAddressError, null);
  if (elements.suiteUnitError)
    showAddressVerificationFieldError(elements.suiteUnitError, null);
  if (elements.addressCityError)
    showAddressVerificationFieldError(elements.addressCityError, null);
  if (elements.addressProvinceError)
    showAddressVerificationFieldError(elements.addressProvinceError, null);
  if (elements.postalCodeError)
    showAddressVerificationFieldError(elements.postalCodeError, null);
}

async function handleAddressVerificationSubmit(e) {
  console.log("Address verification form submitted");
  e.preventDefault();
  e.stopPropagation();

  // Debug: Check if elements exist
  if (!elements.businessNameInput) {
    console.error("businessNameInput not found");
    return false;
  }
  if (!elements.streetAddressInput) {
    console.error("streetAddressInput not found");
    return false;
  }
  if (!elements.suiteUnitInput) {
    console.error("suiteUnitInput not found");
    return false;
  }
  if (!elements.addressCityInput) {
    console.error("addressCityInput not found");
    return false;
  }
  if (!elements.addressProvinceInput) {
    console.error("addressProvinceInput not found");
    return false;
  }
  if (!elements.postalCodeInput) {
    console.error("postalCodeInput not found");
    return false;
  }

  // Clear previous errors
  if (elements.businessNameError)
    showAddressVerificationFieldError(elements.businessNameError, null);
  if (elements.streetAddressError)
    showAddressVerificationFieldError(elements.streetAddressError, null);
  if (elements.suiteUnitError)
    showAddressVerificationFieldError(elements.suiteUnitError, null);
  if (elements.addressCityError)
    showAddressVerificationFieldError(elements.addressCityError, null);
  if (elements.addressProvinceError)
    showAddressVerificationFieldError(elements.addressProvinceError, null);
  if (elements.postalCodeError)
    showAddressVerificationFieldError(elements.postalCodeError, null);

  // Get values
  const businessName = elements.businessNameInput.value;
  const streetAddress = elements.streetAddressInput.value;
  const suiteUnit = elements.suiteUnitInput.value;
  const city = elements.addressCityInput.value;
  const province = elements.addressProvinceInput.value;
  const postalCode = elements.postalCodeInput.value.trim().toUpperCase();

  // Validate
  const businessNameError = validateBusinessName(businessName);
  const streetAddressError = validateStreetAddress(streetAddress);
  const cityError = validateAddressCity(city);
  const provinceError = validateAddressProvince(province);
  const postalCodeError = validatePostalCode(postalCode);

  let hasErrors = false;

  if (businessNameError && elements.businessNameError) {
    showAddressVerificationFieldError(
      elements.businessNameError,
      businessNameError
    );
    hasErrors = true;
  }

  if (streetAddressError && elements.streetAddressError) {
    showAddressVerificationFieldError(
      elements.streetAddressError,
      streetAddressError
    );
    hasErrors = true;
  }

  if (cityError && elements.addressCityError) {
    showAddressVerificationFieldError(elements.addressCityError, cityError);
    hasErrors = true;
  }

  if (provinceError && elements.addressProvinceError) {
    showAddressVerificationFieldError(
      elements.addressProvinceError,
      provinceError
    );
    hasErrors = true;
  }

  if (postalCodeError && elements.postalCodeError) {
    showAddressVerificationFieldError(
      elements.postalCodeError,
      postalCodeError
    );
    hasErrors = true;
  }

  if (hasErrors) return;

  // Disable submit button
  elements.addressVerificationButton.disabled = true;
  elements.addressVerificationButton.textContent = "Verifying...";

  try {
    // Show loading
    showAddressVerificationLoading();

    // Submit verification with separate fields
    const result = await submitAddressVerification(
      streetAddress,
      suiteUnit,
      city,
      province,
      postalCode,
      businessName
    );

    // Show results
    showAddressVerificationResults(result);
  } catch (error) {
    console.error("Address verification error:", error);
    showAddressVerificationError(
      error.message || "Failed to verify address. Please try again."
    );
  } finally {
    elements.addressVerificationButton.disabled = false;
    elements.addressVerificationButton.textContent = "Verify Address";
  }

  return false;
}

// ===========================
// Event Listeners
// ===========================
function initEventListeners() {
  // Theme toggle
  elements.darkModeToggle.addEventListener("click", toggleTheme);

  // Tab switching
  elements.tabButtons.forEach((button) => {
    button.addEventListener("click", () => switchTab(button.dataset.tab));
  });

  // Setup link in warning banner (if present)
  if (elements.setupLink) {
    elements.setupLink.addEventListener("click", (e) => {
      e.preventDefault();
      switchTab("setup");
    });
  }

  // Form submission
  elements.form.addEventListener("submit", handleSubmit);

  // Auto-generate email when full name changes
  elements.fullNameInput.addEventListener("input", autoGenerateEmail);
  elements.fullNameInput.addEventListener("blur", autoGenerateEmail);

  // New report buttons (top and bottom)
  elements.newReportButton.addEventListener("click", resetForm);
  if (elements.newReportButtonBottom) {
    elements.newReportButtonBottom.addEventListener("click", resetForm);
  }

  // Retry button
  elements.retryButton.addEventListener("click", resetForm);

  // Drive configuration
  elements.saveDriveButton.addEventListener("click", saveDriveConfiguration);
  elements.clearDriveButton.addEventListener("click", clearDriveConfiguration);

  // Address verification form submission
  if (elements.addressVerificationForm) {
    elements.addressVerificationForm.addEventListener(
      "submit",
      handleAddressVerificationSubmit
    );
    console.log("Address verification form event listener attached");
  } else {
    console.error("Address verification form not found!");
  }

  // Postal code auto-formatting
  if (elements.postalCodeInput) {
    elements.postalCodeInput.addEventListener("input", (e) => {
      const formatted = formatPostalCode(e.target.value);
      e.target.value = formatted;
    });
  }

  // Address verification retry button
  if (elements.addressVerificationRetryButton) {
    elements.addressVerificationRetryButton.addEventListener(
      "click",
      resetAddressVerificationForm
    );
  }

  // Address verification new search button
  if (elements.addressVerificationNewSearchButton) {
    elements.addressVerificationNewSearchButton.addEventListener(
      "click",
      resetAddressVerificationForm
    );
  }
}

// ===========================
// URL Parameter Population
// ===========================
function populateFromURLParams() {
  try {
    const urlParams = new URLSearchParams(window.location.search);

    // Extract parameters
    const fullName = urlParams.get("fullName");
    const email = urlParams.get("email");
    const city = urlParams.get("city");
    const companyName = urlParams.get("companyName");

    // Check if we have any parameters to populate
    if (!fullName && !email && !city && !companyName) {
      return; // No URL parameters, nothing to do
    }

    // Get form elements directly (in case elements object isn't ready)
    const fullNameInput = document.getElementById("fullName");
    const emailInput = document.getElementById("email");
    const cityInput = document.getElementById("city");
    const companyNameInput = document.getElementById("companyName");

    // Populate form fields if values exist
    let populated = false;

    if (fullName && fullNameInput) {
      fullNameInput.value = decodeURIComponent(fullName);
      populated = true;
      console.log("Populated fullName:", fullName);
    }

    if (email && emailInput) {
      emailInput.value = decodeURIComponent(email);
      populated = true;
      console.log("Populated email:", email);
    }

    if (city && cityInput) {
      cityInput.value = decodeURIComponent(city);
      populated = true;
      console.log("Populated city:", city);
    }

    if (companyName && companyNameInput) {
      companyNameInput.value = decodeURIComponent(companyName);
      populated = true;
      console.log("Populated companyName:", companyName);
    }

    // If any fields were populated, clean the URL (remove query params)
    if (populated) {
      // Clean URL without reloading the page
      const cleanUrl = window.location.pathname + window.location.hash;
      window.history.replaceState({}, document.title, cleanUrl);

      console.log("Form populated from URL parameters:", {
        fullName,
        email,
        city,
        companyName,
      });
    } else {
      console.warn("URL parameters found but form elements not available:", {
        fullName,
        email,
        city,
        companyName,
      });
    }
  } catch (error) {
    console.error("Error populating form from URL parameters:", error);
  }
}

// ===========================
// Service Account Email Update
// ===========================
function updateServiceAccountEmail() {
  if (!FIREBASE_CONFIG || !FIREBASE_CONFIG.projectId) {
    console.warn(
      "Project ID not available, cannot update service account email"
    );
    return;
  }

  const serviceAccountEmail = `functions-sa@${FIREBASE_CONFIG.projectId}.iam.gserviceaccount.com`;

  // Update the email display
  const emailDiv = document.getElementById("serviceAccountEmail");
  if (emailDiv) {
    emailDiv.textContent = serviceAccountEmail;
  }

  // Update the email in troubleshooting section
  const emailCode = document.getElementById("serviceAccountEmailCode");
  if (emailCode) {
    emailCode.textContent = serviceAccountEmail;
  }
}

// ===========================
// Initialization
// ===========================
async function init() {
  // Load configuration first (from firebase-config.json generated by Terraform)
  const configLoaded = await loadConfig();
  if (!configLoaded) {
    console.error("Failed to load configuration. Application cannot start.");
    return;
  }

  // Initialize Firebase authentication
  await initializeAuth();

  initTheme();
  initEventListeners();
  checkDriveConfiguration();
  loadDriveConfiguration();
  updateServiceAccountEmail();

  // Populate form from URL parameters (for Chrome extension integration)
  // Use setTimeout to ensure DOM elements are fully available
  setTimeout(() => {
    populateFromURLParams();
  }, 100);

  console.log("Origination Intelligence Platform initialized");
  console.log("API URL:", API_URL);
}

// Start the app when DOM is ready
if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", init);
} else {
  init();
}
